export const CRANE_FRAMEWORK_BODY_HTML = "<h1>Astrological Weather Forecasting — Framework Model</h1>\n<div class=\"subtitle\">\n  Synthesized from Rev. Pam Crane, \"Weather Forecasting\" (The Adventurous Astrologer) —\n  Sources: C.C. Zain (1949), Kris Brandt Riske (1997), Crane's own chart analyses.<br>\n  For backtesting against historical geophysical events. Do not add interpretations not present in source.\n</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>1 — Sign & Planet Weather Profiles (Zain / Crane)</h2>\n<div class=\"note\">These apply to the sign on the IC, 1st house, and to planets occupying or ruling those houses. They are baseline indicators when unafflicted.</div>\n\n<table>\n  <thead>\n    <tr>\n      <th>Sign</th>\n      <th>Traditional Ruler</th>\n      <th>Modern Ruler</th>\n      <th>Temperature</th>\n      <th>Moisture</th>\n      <th>Wind</th>\n      <th>Other</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>Aries</strong></td>\n      <td>Mars</td>\n      <td>—</td>\n      <td><span class=\"tag hot\">Hot</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag wind\">Fairly Windy</span></td>\n      <td>Extreme, catalytic, clear, bright</td>\n    </tr>\n    <tr>\n      <td><strong>Taurus</strong></td>\n      <td>Venus</td>\n      <td>—</td>\n      <td><span class=\"tag mild\">Mild</span></td>\n      <td><span class=\"tag wet\">Productively Wet</span></td>\n      <td><span class=\"tag calm\">Calm</span></td>\n      <td>Temperate, cloudy</td>\n    </tr>\n    <tr>\n      <td><strong>Gemini</strong></td>\n      <td>Mercury</td>\n      <td>—</td>\n      <td><span class=\"tag cold\">Cold</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag wind\">Very Windy</span></td>\n      <td>Variable</td>\n    </tr>\n    <tr>\n      <td><strong>Cancer</strong></td>\n      <td>Moon</td>\n      <td>—</td>\n      <td><span class=\"tag cold\">Cold</span></td>\n      <td><span class=\"tag wet\">Very Wet</span></td>\n      <td><span class=\"tag calm\">Fairly Still</span></td>\n      <td>—</td>\n    </tr>\n    <tr>\n      <td><strong>Leo</strong></td>\n      <td>Sun</td>\n      <td>—</td>\n      <td><span class=\"tag hot\">Warm</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag calm\">Very Still</span></td>\n      <td>Sunny, clear, bright; thundery potential</td>\n    </tr>\n    <tr>\n      <td><strong>Virgo</strong></td>\n      <td>Mercury</td>\n      <td>Ceres (proposed)</td>\n      <td><span class=\"tag cold\">Cold</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag wind\">Windy / Blustery</span></td>\n      <td>Ceres as co-ruler adds seasonal/crop dimension</td>\n    </tr>\n    <tr>\n      <td><strong>Libra</strong></td>\n      <td><em>Not Venus (per Zain)</em></td>\n      <td>—</td>\n      <td><span class=\"tag cold\">Cool</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag wind\">Windy</span></td>\n      <td>Mild, bright, refreshing</td>\n    </tr>\n    <tr>\n      <td><strong>Scorpio</strong></td>\n      <td>Mars</td>\n      <td>Pluto</td>\n      <td>—</td>\n      <td><span class=\"tag wet\">Wet / Drizzly</span></td>\n      <td>—</td>\n      <td><span class=\"tag extreme\">Extreme / Destructive</span></td>\n    </tr>\n    <tr>\n      <td><strong>Sagittarius</strong></td>\n      <td>Jupiter</td>\n      <td>—</td>\n      <td><span class=\"tag hot\">Warm / Balmy</span></td>\n      <td><span class=\"tag dry\">Dryish</span></td>\n      <td><span class=\"tag wind\">Breezy</span></td>\n      <td>Pleasant, bright</td>\n    </tr>\n    <tr>\n      <td><strong>Capricorn</strong></td>\n      <td>Saturn</td>\n      <td>—</td>\n      <td><span class=\"tag cold\">Very Cold</span></td>\n      <td><span class=\"tag wet\">Wet</span></td>\n      <td><span class=\"tag calm\">Still</span></td>\n      <td><span class=\"tag extreme\">Unseasonable, disagreeable, destructive</span></td>\n    </tr>\n    <tr>\n      <td><strong>Aquarius</strong></td>\n      <td>Saturn</td>\n      <td>Uranus</td>\n      <td><span class=\"tag cold\">Cold</span></td>\n      <td><span class=\"tag dry\">Dry</span></td>\n      <td><span class=\"tag wind\">Squally / Gusty</span></td>\n      <td>Changeable, crisp, thundery</td>\n    </tr>\n    <tr>\n      <td><strong>Pisces</strong></td>\n      <td>Jupiter</td>\n      <td>Neptune</td>\n      <td><span class=\"tag cold\">Cool</span></td>\n      <td><span class=\"tag wet\">Wet / Misty / Foggy</span></td>\n      <td><span class=\"tag calm\">Calm</span></td>\n      <td><span class=\"tag extreme\">Freakish; uncontrollable flooding (Mutable Water)</span></td>\n    </tr>\n  </tbody>\n</table>\n\n<div class=\"note\">\n  <strong>Mercury as Temperature Indicator (Crane's observation):</strong> Mercury's sign placement may indicate temperature as well as wind. Mercury in Sagittarius = mild; Mercury in Capricorn/Aquarius = cold. Mercury stationary = prolonged/stuck conditions. Needs systematic testing.\n</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>2 — Chart Hierarchy (Layer System)</h2>\n<div class=\"note\">Apply in this sequence. Each layer refines the previous. Location-specific Dwad angles always override generic reading.</div>\n\n<table>\n  <thead>\n    <tr><th>#</th><th>Chart Type</th><th>Trigger</th><th>Primary Use</th><th>Time Scope</th><th>Priority</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td><strong>Cardinal Solar Ingress</strong> (Aries/Cancer/Libra/Capricorn)</td>\n      <td>Sun enters cardinal sign</td>\n      <td>Temperature overview for the season; also gives overview of moisture</td>\n      <td>~3 months</td>\n      <td class=\"p1\">P1 — Highest</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td><strong>Lunations</strong> (New &amp; Full Moons, Quarters)</td>\n      <td>4× per month</td>\n      <td>Moisture / dryness within each ~7-day period</td>\n      <td>~7 days</td>\n      <td class=\"p1\">P1 — Highest</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td><strong>Mercury Sign Ingress</strong></td>\n      <td>Mercury changes sign (direct or retrograde)</td>\n      <td>Wind / stillness for Mercury's sojourn in that sign; possibly temperature</td>\n      <td>Variable (2–8 wks)</td>\n      <td class=\"p2\">P2 — High</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td><strong>Solar Eclipse</strong></td>\n      <td>New Moon eclipse</td>\n      <td>Major weather events; freak/extreme conditions</td>\n      <td>Up to 6 months</td>\n      <td class=\"p1\">P1 — Highest (when present)</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td><strong>Moon Sign Ingress</strong></td>\n      <td>Moon changes sign (~every 2.5 days)</td>\n      <td>Fine-tuning; additional layer of precision (Crane's addition — not in Zain/Riske)</td>\n      <td>~2.5 days</td>\n      <td class=\"p2\">P2 — High</td>\n    </tr>\n    <tr>\n      <td>6</td>\n      <td><strong>Civil Chart (0h00 local time)</strong></td>\n      <td>Daily; any given day</td>\n      <td>Short-term conditions for that specific day</td>\n      <td>~1 day</td>\n      <td class=\"p3\">P3 — Supporting</td>\n    </tr>\n    <tr>\n      <td>7</td>\n      <td><strong>Node Sign Change</strong></td>\n      <td>True Nodes change signs</td>\n      <td>Possibly a weather indicator — needs testing (Crane's observation)</td>\n      <td>~18 months</td>\n      <td class=\"p3\">P3 — Tentative</td>\n    </tr>\n    <tr>\n      <td>8</td>\n      <td><strong>Dwad of any chart above</strong></td>\n      <td>Applied to any chart type</td>\n      <td>Intensification / correction / local specificity (varies considerably by location)</td>\n      <td>Same as parent chart</td>\n      <td class=\"p1\">P1 — Always check</td>\n    </tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>3 — Key Factors Within Each Chart (Priority Order)</h2>\n<div class=\"grid2\">\n  <div class=\"card\">\n    <h4>🏠 4th House — Primary Key</h4>\n    <ul>\n      <li>Sign on IC cusp</li>\n      <li>Planets in the 4th house</li>\n      <li>Ruler of IC — its sign, house, aspects</li>\n      <li>Dwad IC (location-specific)</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>🏠 1st House — Secondary Key</h4>\n    <ul>\n      <li>Sign on Ascendant</li>\n      <li>Planets in 1st house</li>\n      <li>Ruler of Ascendant — sign, house, aspects</li>\n      <li>Dwad Ascendant (varies greatly by location)</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>📐 Angular Planets</h4>\n    <ul>\n      <li>All planets on or near MC, IC, ASC, DSC have key roles</li>\n      <li>Degree of angularity matters (exact = more powerful)</li>\n      <li>Dwad angular planets compound radix angularity</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>☀️ Dispositor Chain</h4>\n    <ul>\n      <li>Dispositor of the Sun (in seasonal ingress)</li>\n      <li>Dispositor of Mercury (in Mercury ingress charts)</li>\n      <li>Dispositor of the Moon (in lunar charts)</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>🌑 Nodal Axis</h4>\n    <ul>\n      <li>Nodes angular (horizon or meridian) = warning of significant event</li>\n      <li>South Node rising = particularly challenging</li>\n      <li>South Node eclipse = knockout blow (especially if economic/national impact)</li>\n      <li>Dwad Nodes on radix angles = intensification</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>📏 Degree Directions (Timing)</h4>\n    <ul>\n      <li><strong>1° = 1 day</strong> from ingress date</li>\n      <li>Count degrees from MC/ASC to any planet = days until that condition manifests</li>\n      <li>Check Minor Progressions of Ingress charts for seasonal changes</li>\n      <li>Check Daily Progressions for daily conditions</li>\n    </ul>\n  </div>\n</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>4 — Celestial Bodies to Watch</h2>\n<table>\n  <thead>\n    <tr><th>Body</th><th>Category</th><th>Weather Role (from source)</th><th>Confidence</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>Sun</strong></td>\n      <td>Traditional</td>\n      <td>Seasonal ruler in Temperature Charts; Leo = warm/dry/still/thundery</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Moon</strong></td>\n      <td>Traditional</td>\n      <td>Moisture ruler in Lunation Charts; Cancer = cold/wet/still; South Node = challenging; own sign = powerful</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Mercury</strong></td>\n      <td>Traditional</td>\n      <td>Wind ruler in Mercury Ingress Charts; possibly temperature too (Crane's addition)</td>\n      <td class=\"confirm\">Established (wind); <span class=\"ambig\">Tentative (temperature)</span></td>\n    </tr>\n    <tr>\n      <td><strong>Venus</strong></td>\n      <td>Traditional</td>\n      <td>Taurus = mild/temperate/wet; Scorpio = adds moisture/destruction; Libra ruler debated</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Mars</strong></td>\n      <td>Traditional</td>\n      <td>Aries = hot/dry; configured with Saturn = severe storm component; on MC = warming</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Jupiter</strong></td>\n      <td>Traditional</td>\n      <td>\"Jupiter Pluvius\" — heavy rain even in apparently dry charts; in Scorpio/water = major precipitation; IC = very hot (1987 storm); thunderbolts</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Saturn</strong></td>\n      <td>Traditional</td>\n      <td>Cold; configured with Moon = cold; with Sun at IC = cold/snow that day; in dry sign at ingress = drought potential</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Uranus</strong></td>\n      <td>Modern</td>\n      <td>Aquarius = squally/changeable/thundery; angular = unusual/freak conditions; in 4th = unusual/changeable</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Neptune</strong></td>\n      <td>Modern</td>\n      <td>Pisces = misty/foggy/freakish; IC = freak conditions; rising = outlandish; with Moon = snowy possibility</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Pluto</strong></td>\n      <td>Modern</td>\n      <td>Extremes; with Sun at Winter Ingress = challenging weather; angular = transformative weather change; transit to national Sun = extended extreme (drought/flood)</td>\n      <td class=\"confirm\">Established</td>\n    </tr>\n    <tr>\n      <td><strong>Ceres ⚠️</strong></td>\n      <td>Extended (Crane adds)</td>\n      <td>Proposed co-ruler of Virgo. Angular in nearly every major weather event studied: drought (1976, 2003), flood (1953), storm (1987), freeze (1963, 2012). May indicate crop/ecosystem impact. IC = cold (south-east England). Setting = change (thaw). Angular = watch weather carefully.</td>\n      <td class=\"ambig\">High Candidate — not in Zain/Riske, consistent in Crane's case studies</td>\n    </tr>\n    <tr>\n      <td><strong>Chiron</strong></td>\n      <td>Extended (Crane adds)</td>\n      <td>Appears at major disruption/unusual weather events; angular = pain/disruption; may represent the wild/natural environment; \"maverick\" weather introduction</td>\n      <td class=\"ambig\">Candidate — recurring but not systematically codified</td>\n    </tr>\n    <tr>\n      <td><strong>Sedna</strong></td>\n      <td>Extended (Crane adds)</td>\n      <td>Sea-goddess myths = mighty storms. Prominent in 1987 Hurricane (with Uranus, rising), North Sea Flood 1953 (opposite rising Saturn/Neptune), London Tornado 1091 (dwad ASC contact). Associated with catastrophic storm events near water.</td>\n      <td class=\"ambig\">Candidate — consistent in extreme storm events</td>\n    </tr>\n    <tr>\n      <td><strong>Eris</strong></td>\n      <td>Extended (Crane adds)</td>\n      <td>Angular in major disasters; IC in drought 2003 (Aries); doubly angular in 1962-63 freeze. Discord/destructive energy.</td>\n      <td class=\"ambig\">Candidate — needs more data points</td>\n    </tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>5 — High-Signal Planetary Combinations</h2>\n<div class=\"note\">These are patterns that Crane identifies as consistently producing specific weather outcomes across multiple case studies. Treat as testable hypotheses.</div>\n\n<table>\n  <thead>\n    <tr><th>Pattern</th><th>Weather Signal</th><th>Evidence (Crane)</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>Sun conjunct Pluto at Winter Ingress</strong></td>\n      <td><span class=\"tag extreme\">Extreme cold / challenging winter</span></td>\n      <td>UK winters 2009-10, 2010-11, 2011-12 — all had Pluto near Capricorn Sun at ingress</td>\n    </tr>\n    <tr>\n      <td><strong>Saturn square Moon (angular)</strong></td>\n      <td><span class=\"tag cold\">Intense cold</span></td>\n      <td>1962-63 (square at ingress), multiple freeze events</td>\n    </tr>\n    <tr>\n      <td><strong>Mars opposite Saturn (both angular)</strong></td>\n      <td><span class=\"tag extreme\">Severe storm / violent conditions</span></td>\n      <td>1946-47 freeze (Sun/Mars at Aquarius IC vs Saturn/Pluto at MC); general storm indicator</td>\n    </tr>\n    <tr>\n      <td><strong>Pluto transiting national Sun</strong></td>\n      <td><span class=\"tag extreme\">Extended extreme — drought or flood lasting months/years</span></td>\n      <td>1975-76 drought: Pluto moving over 9°-10° Libra square UK Capricorn Sun entire period</td>\n    </tr>\n    <tr>\n      <td><strong>Jupiter Pluvius in water sign / angular</strong></td>\n      <td><span class=\"tag wet\">Heavy precipitation despite other indicators</span></td>\n      <td>1962-63 (Scorpio), 1946-47, 2003 (Scorpio at ingress), 1953 flood (Taurus, wet)</td>\n    </tr>\n    <tr>\n      <td><strong>Moon's South Node rising / angular</strong></td>\n      <td><span class=\"tag extreme\">Severe national impact; \"knockout blow\"</span></td>\n      <td>Dec 2009 Capricorn Ingress (South Node rising in Cancer = snow/ice catastrophe); 1962-63</td>\n    </tr>\n    <tr>\n      <td><strong>Uranus angular / on IC</strong></td>\n      <td><span class=\"tag extreme\">Unusual, freak, changeable weather; thunder-snow</span></td>\n      <td>2006 thunder-snow (Uranus near New Moon IC); 1987 storm (Uranus rising at ingress)</td>\n    </tr>\n    <tr>\n      <td><strong>Mercury conjunct Pluto (IC or angular)</strong></td>\n      <td><span class=\"tag extreme\">Violent storm event onset</span></td>\n      <td>1987 storm: Mercury/Pluto conjunction at Scorpio IC at 2am when storm made landfall</td>\n    </tr>\n    <tr>\n      <td><strong>Ceres angular + Pluto/Saturn configured</strong></td>\n      <td><span class=\"tag extreme\">Crop failure / ecosystem devastation / destructive drought or freeze</span></td>\n      <td>2003 drought (Ceres at ingress IC directed to progressd chart), 1976 drought (Ceres in 4th in Gemini), 1962-63 (Ceres at MC opposite Chiron)</td>\n    </tr>\n    <tr>\n      <td><strong>Neptune at IC / angular</strong></td>\n      <td><span class=\"tag wet\">Freak conditions; whiteout; sea fog; chaos</span></td>\n      <td>1962-63 (Neptune setting with Venus at IC); 1953 flood (Neptune/Saturn rising); 1987 (Neptune/Jupiter setting at eclipse)</td>\n    </tr>\n    <tr>\n      <td><strong>Sun/Saturn at IC (civil chart dawn)</strong></td>\n      <td><span class=\"tag cold\">That day: severe cold / snow onset</span></td>\n      <td>Feb 1963: day that began with Sun/Saturn hand-in-hand at IC was worst continental cold outbreak</td>\n    </tr>\n    <tr>\n      <td><strong>Sedna + Mercury/Pluto (Dwad or radix)</strong></td>\n      <td><span class=\"tag extreme\">Catastrophic storm, especially coastal/maritime</span></td>\n      <td>1987: Sedna on MC opposite Mercury/Pluto IC at time of landfall; 1953: Sedna opposite rising planets</td>\n    </tr>\n    <tr>\n      <td><strong>Dwad Mutable Grand Cross</strong></td>\n      <td><span class=\"tag extreme\">Unforgettable autumn / season of extremes</span></td>\n      <td>1987 Libra Ingress Dwad: Sagittarian Moon, Saturn, Jupiter/Neptune, Uranus in mutable GC</td>\n    </tr>\n    <tr>\n      <td><strong>Saturn + Uranus + Ceres angular in Minor Progression</strong></td>\n      <td><span class=\"tag extreme\">Major weather event on that day of year</span></td>\n      <td>1987: Minor Progression of eclipse chart put Saturn/Uranus/Ceres on Descendant at storm date</td>\n    </tr>\n    <tr>\n      <td><strong>Fire signs dominant at Summer Ingress + Pluto angular</strong></td>\n      <td><span class=\"tag hot\">Severe drought / record heat</span></td>\n      <td>2003 Cancer Ingress: Sun/Saturn square Aries Moon + Pluto rising = European drought/heatwave</td>\n    </tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>6 — The Dwad Integration Rules</h2>\n<div class=\"grid2\">\n  <div class=\"card\">\n    <h4>What the Dwad Adds</h4>\n    <ul>\n      <li>Corrects misleading radix readings</li>\n      <li>Provides location-specific precision (Dwad angles vary widely even 50 miles apart)</li>\n      <li>Reveals hidden extremity not visible in radix</li>\n      <li>Connects otherwise unlinked radix bodies</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>Key Dwad Contacts to Check</h4>\n    <ul>\n      <li>Dwad IC landing on radix angular body</li>\n      <li>Dwad ASC landing on radix angular body</li>\n      <li>Radix/Dwad cross-contacts (body + its Dwad both hitting same degree)</li>\n      <li>Dwad Nodes on radix angles</li>\n      <li>Dwad Moon / Dwad Saturn at horizon or meridian</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>Examples Where Dwad Was Decisive</h4>\n    <ul>\n      <li>2011-12 London vs Liverpool: Scorpio vs Libra on Dwad IC explained north-south temperature split</li>\n      <li>1962-63: Dwad Uranus conjunct radix Moon at MC = blizzard severity</li>\n      <li>1091 Tornado: Dwad Mars/Jupiter conjunct radix ASC = catastrophe not visible in radix</li>\n      <li>1987 Storm: Dwad Mars/IC = violent weather specific to south-east</li>\n    </ul>\n  </div>\n  <div class=\"card\">\n    <h4>Warning</h4>\n    <ul>\n      <li>Dwad angles are highly location-sensitive. Always set for the specific city/region being studied.</li>\n      <li>A Dwad reading for London may be completely different from Liverpool, even for same chart.</li>\n      <li>Do not apply Dwad readings generically across a country.</li>\n    </ul>\n  </div>\n</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>7 — Multi-Zodiac Protocol</h2>\n<div class=\"note\">Crane uses Tropical, Sidereal, and Draconic zodiacs together. The dominant zodiac can shift by event type.</div>\n<table>\n  <thead>\n    <tr><th>Zodiac</th><th>Primary Domain</th><th>When Dominant</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>Tropical</strong></td>\n      <td>Physical, seasonal weather conditions</td>\n      <td>Most events; default first reading</td>\n    </tr>\n    <tr>\n      <td><strong>Sidereal</strong></td>\n      <td>Physical conditions with historic/environmental impact</td>\n      <td>Crane: 1946-47 winter was a \"Sidereal winter\" — Tropical gave misleading fire sign reading; Sidereal showed Scorpio stellium at MC / Capricorn rising</td>\n    </tr>\n    <tr>\n      <td><strong>Draconic</strong></td>\n      <td>Collective karma; historical record; national destiny; suffering at mass scale</td>\n      <td>When weather has historic or karmic national significance; when human suffering is extreme. Draconic Chiron/Uranus at MC = 1962-63 blizzard's cultural imprint.</td>\n    </tr>\n  </tbody>\n</table>\n<div class=\"warn\">Crane's rule: \"either-or may be a mistake; 'both-and' is the more likely route to truth, with context prescribing the dominant zodiac.\" Use all three, weight by context.</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>8 — Timing Techniques</h2>\n<table>\n  <thead>\n    <tr><th>Technique</th><th>Rule</th><th>Use</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>1° Direction from Ingress</strong></td>\n      <td>1° of arc from any angle = 1 day from ingress date. Count degrees from MC/ASC to a planet to find when that condition manifests in the season.</td>\n      <td>Timing cold snaps, storms, thaws within a season. E.g. Saturn 35° from MC at Winter Ingress = cold arriving ~Jan 26 (35 days after Dec 22)</td>\n    </tr>\n    <tr>\n      <td><strong>Minor Progression of Ingress</strong></td>\n      <td>Progress the ingress chart at minor rate to find distinctive changes within the season</td>\n      <td>Confirms or reveals weather changes within the ~3-month window; less reliable than directions but useful double-check</td>\n    </tr>\n    <tr>\n      <td><strong>Daily Progression of Ingress</strong></td>\n      <td>Progress ingress to a specific date (e.g. hottest day on record)</td>\n      <td>Crane used this for 2003 drought: Daily Progressed Ingress to Aug 10 put MC at 9° Sag (with Sedna) and dpIC at Ceres. Very specific local testing.</td>\n    </tr>\n    <tr>\n      <td><strong>Transit to Ingress Positions</strong></td>\n      <td>Transit planets over ingress chart positions trigger seasonal events</td>\n      <td>E.g. Venus transiting Mercury/MC at 1987 autumn ingress around storm date; Mars transit to ingress Moon</td>\n    </tr>\n    <tr>\n      <td><strong>Directed Descendant to Ingress Planet</strong></td>\n      <td>Ingress Descendant directed 1°/day to conjunct a natal planet = seasonal transition or event</td>\n      <td>1946-47: mid-March Ingress Desc directed to Scorpio Jupiter (rain ruler) = end of freeze and start of flooding</td>\n    </tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>9 — Historical Event Test Log</h2>\n<div class=\"note\">From Crane's article. Use this as your baseline calibration set. Status codes:\n  <span class=\"confirm\">■ Confirmed</span> (Crane explicitly verifies pattern matched outcome) |\n  <span class=\"ambig\">■ Ambiguous</span> (pattern present but reading complex/mixed) |\n  <span class=\"fail\">■ Failed/Unclear</span> (pattern did not clearly map to outcome)\n</div>\n\n<table>\n  <thead>\n    <tr><th>Event</th><th>Date / Location</th><th>Type</th><th>Key Indicators Present</th><th>Status</th></tr>\n  </thead>\n  <tbody>\n    <tr class=\"event-row\">\n      <td><strong>UK Summer Drought 1976</strong></td>\n      <td>Summer 1976, UK</td>\n      <td>Drought / Extreme heat</td>\n      <td>Pluto transiting UK natal Sun (9°-10° Libra) for entire period; Sun/Pluto square at Jan 1 1975 & 1976 + Pluto on ASC 1975; Fire signs dominant at Summer Ingress 1976; Saturn/Leo ASC; Mars at Dwad IC; Ceres in 4th (Gemini) at Autumn Ingress 1975; Pluto angular at May Ingress</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr>\n      <td><strong>UK Winter 1962-63</strong></td>\n      <td>Dec 26 1962 – Mar 6 1963, UK</td>\n      <td>Extreme freeze / blizzard</td>\n      <td>Winter Ingress: Capricorn rising, Scorpio Moon culminating, Taurus IC (wet), Venus/Neptune in Scorpio (setting), Saturn in Aquarius square Moon + South Node; Dwad: Uranus conjunct Moon at MC; Boxing Day NM in 4th configured with Uranus/Chiron/Jupiter opposition; Draconic Chiron bang on Tropical MC + Uranus opposite; Draconic Sedna near Tropical ASC</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr class=\"event-row\">\n      <td><strong>UK Winter 1946-47</strong></td>\n      <td>Jan–Mar 1947, UK</td>\n      <td>Extreme freeze + catastrophic flooding (thaw)</td>\n      <td>Tropical: Fire signs prominent — misleading re: cold. Sidereal: Scorpio stellium at MC, Capricorn rising, Saturn/Pluto in wet Cancer = accurate. Sun/Mars at Aquarius IC vs Saturn at MC on Feb 1. Mercury stationary in Pisces at worst blizzard. Ceres with Sun (March 5). Tropical Eris on Draconic IC at winter ingress.</td>\n      <td><span class=\"ambig\">Ambiguous (Tropical misleading; Sidereal confirmed)</span></td>\n    </tr>\n    <tr>\n      <td><strong>North Sea Flood 1953</strong></td>\n      <td>Jan 31 – Feb 1 1953, UK/Netherlands coast</td>\n      <td>Catastrophic storm surge / flood (worst UK 20C natural disaster)</td>\n      <td>1952 Winter Ingress: Scorpio IC (Canvey Island), Mercury in 4th opposite Gemini Ceres, Moon in Pisces setting; Dwad Chiron at MC, Saturn/Neptune at Dwad IC; Aquarius Sun Ingress: Nodes on horizon, Ceres/Gemini IC + Dwad Moon; Full Moon = South Node total lunar eclipse, angular all along Channel; Mercury/Pluto Dwad conjunction hitting DSC at storm onset; Moon conjunct Pluto at peak flooding; Sedna opposite Saturn/Neptune rising</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr class=\"event-row\">\n      <td><strong>London Tornado 1091</strong></td>\n      <td>Oct 17 (OS) 1091, London</td>\n      <td>Tornado / destructive storm</td>\n      <td>New Moon 2 days prior: Aquarius at IC (electrical/squalls), Scorpio ASC, Saturn in Cancer with Neptune (freak weather), Mars in Gemini (wind); Dwad: NM repositioned Virgo/MC (heat/moisture), Mars/Jupiter conjunct ASC, Uranus/Pluto at Dwad Aries ASC, Dwad MC with Saturn/Neptune, Chiron at Dwad IC, Dwad Pluto opposite radix NM; Mercury aligned with Eris at Dwad</td>\n      <td><span class=\"confirm\">Confirmed (Dwad decisive)</span></td>\n    </tr>\n    <tr>\n      <td><strong>\"Hurricane\" 1987</strong></td>\n      <td>Oct 16 1987 (~2am), SE England</td>\n      <td>Catastrophic windstorm (worst since 1703)</td>\n      <td>Autumn Ingress: Uranus/Ceres rising in Sag, Jupiter in Aries at IC, solar eclipse just occurred, Chiron setting; Dwad: Mars/IC (SE England), South Node stellium + Dwad ASC; Dwad Mutable GC (Moon-Sag, Saturn, Jupiter/Neptune, Uranus); Minor Progression: Sun/South Node with ASC, Moon to Mercury/Jupiter opposition, Neptune at IC; Eclipse chart: Sun/Moon/Uranus/Sedna conjunct radix ASC + Dwad ASC; Mercury into Scorpio ingress: Uranus/Ceres at MC, Chiron at IC, Mars setting, Moon with Saturn; 2am landfall: Mercury/Pluto at Scorpio IC + Sedna at MC; Dwad Pluto on radix DSC</td>\n      <td><span class=\"confirm\">Confirmed (multiply redundant signals)</span></td>\n    </tr>\n    <tr class=\"event-row\">\n      <td><strong>European Drought / Heatwave 2003</strong></td>\n      <td>Summer 2003, Europe (esp. France/Kent)</td>\n      <td>Record drought / 40,000+ deaths</td>\n      <td>Cancer Ingress: Sun/Saturn square hot Aries Moon; Pluto rising in Sag (Faversham); Eris at Aries IC; Dwad Aries Moon + North Node at IC; Dwad Uranus with radix Aries Moon; Daily Progression to Aug 10: MC = 9° Sag (with Dwad Sedna), dpIC = Ceres; Daily ASC met Neptune; Dwad ASC collected Sun/Saturn + Dwad Sun/Neptune/Pluto; Dwad MC had Mars/Uranus; Jan 1 2003 civil chart: Saturn in Gemini (dry), Venus conjunct hot Mars in Scorpio, Sagittarius Moon with Pluto; Dwad Pluto/Ceres on MC</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr>\n      <td><strong>UK Winter 2011-12</strong></td>\n      <td>Dec 2011 – Feb 2012, UK</td>\n      <td>Mild start → bitter cold / freezing rain Feb</td>\n      <td>Capricorn Ingress: wet signs on 1st/4th, Moon rising (rain), Sun configured with Jupiter/Saturn/Neptune/Chiron (mixed signal), Pluto/Uranus square; Dwad: London has Scorpio Dwad IC (colder) vs Liverpool's Libra (milder) — explains split; Ceres at radix IC; Feb Full Moon: Ceres setting, Pluto at Capricorn IC; Mercury Aquarius ingress Jan 27: T-square Mercury to Saturn/Jupiter; Feb freezing rain: Aquarius Sun tight with Mercury, Capricorn Moon; Directions: Saturn ~35° from MC = cold arriving late Jan</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr class=\"event-row\">\n      <td><strong>Thunder-snow event 2006</strong></td>\n      <td>Mar 1 2006, N. Wales coast</td>\n      <td>Electrical storm + heavy snow</td>\n      <td>New Moon in Pisces (Feb 28) at IC, 1° from Uranus; Jupiter rising in Scorpio; Sedna setting; 10pm: Uranus near New Moon by 1° measure; Saturn on MC opposite Ceres + Chiron; Preceding Winter Ingress (Dec 21 2005): Ceres conjunct Sun, Chiron setting with Venus (IC ruler)</td>\n      <td><span class=\"confirm\">Confirmed</span></td>\n    </tr>\n    <tr>\n      <td><strong>UK Summer 2012 (jet stream south)</strong></td>\n      <td>Aug 2012, UK</td>\n      <td>NW cold/wet vs SE hot/dry split</td>\n      <td>Leo New Moon Aug 17: Mars/Saturn conjunction exact on Libra MC (east); Sag rising; Jupiter in Air; Dwad: dry Virgo ASC + burning Mars/MC in London; N Wales: Dwad ASC/MC both meet Uranus/Cancer; Manchester: Cancer rising, Dwad Saturn/MC; Penzance: Saturn rising at Cancer end; Belfast: New Moon on Dwad ASC; Northumberland: Cancer MC on Saturn; King's Lynn: Leo Dwad ASC/MC = hot/dry</td>\n      <td><span class=\"confirm\">Confirmed (geographic precision via Dwad)</span></td>\n    </tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>10 — Prediction Checklist (Apply to Any Target Date / Location)</h2>\n<div class=\"note\">Run through in order. Note which layer confirms or contradicts others. Flag contradictions for further zodiac / Dwad analysis.</div>\n\n<div class=\"grid2\">\n  <div>\n    <h3>A. Seasonal Context</h3>\n    <ul class=\"checklist\">\n      <li>Identify the most recent Cardinal Ingress (Aries/Cancer/Libra/Capricorn) for your location</li>\n      <li>Read IC sign + planets in 4th → baseline temperature/moisture</li>\n      <li>Read ASC sign + planets in 1st → baseline temperature/wind modifier</li>\n      <li>Note IC ruler, ASC ruler — their signs and aspects</li>\n      <li>Check for angular Pluto (extreme), Saturn (cold), Jupiter (wet/hot), Uranus (freak), Neptune (fog/freak)</li>\n      <li>Check Nodes: are they angular? South Node rising = high-impact event warning</li>\n      <li>Run Dwad for target location — check Dwad IC and Dwad ASC</li>\n      <li>Check Ceres, Chiron, Sedna, Eris — are any angular or in 4th/1st?</li>\n      <li>Use 1°/day direction from ingress to target date. What planets does the MC/ASC reach?</li>\n      <li>Note any eclipses within 6 months of target — read eclipse chart for same location</li>\n    </ul>\n  </div>\n  <div>\n    <h3>B. Monthly / Weekly Refinement</h3>\n    <ul class=\"checklist\">\n      <li>Find the most recent New or Full Moon before target date</li>\n      <li>Read IC + 4th house of that lunation for location → moisture signal</li>\n      <li>Check Mercury sign ingress nearest to target → wind / temperature modifier</li>\n      <li>Note Mercury direct/retrograde + station status (station = prolonged conditions)</li>\n      <li>Check Moon Sign Ingress closest to target → fine-tune</li>\n      <li>Run Dwad for lunation at target location</li>\n    </ul>\n    <h3>C. Daily Conditions</h3>\n    <ul class=\"checklist\">\n      <li>Cast civil chart for 0h00 local time at target location</li>\n      <li>Read IC (Sun always at IC at 0h00 = check its sign and aspects)</li>\n      <li>Note any tight angular aspects (especially Mercury/Pluto, Sun/Saturn, Moon/Pluto)</li>\n      <li>Run Dwad for that civil chart at location</li>\n      <li>Cross-check with Ingress 1°/day direction</li>\n    </ul>\n    <h3>D. Multi-Zodiac Cross-Check</h3>\n    <ul class=\"checklist\">\n      <li>If Tropical reading is ambiguous, check Sidereal chart</li>\n      <li>If event appears to have mass human/historical impact → check Draconic</li>\n      <li>Look for Draconic bodies landing on Tropical angles and vice versa</li>\n    </ul>\n  </div>\n</div>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<h2>11 — Framework Confidence Ratings</h2>\n<table>\n  <thead>\n    <tr><th>Element</th><th>Source</th><th>Test Events in Article</th><th>Confidence</th></tr>\n  </thead>\n  <tbody>\n    <tr><td>Sign/planet temperature & moisture profiles</td><td>Zain 1949</td><td>8/10 events</td><td class=\"confirm\">High</td></tr>\n    <tr><td>4th house / IC as primary key</td><td>Zain 1949, Riske 1997</td><td>10/10 events</td><td class=\"confirm\">Very High</td></tr>\n    <tr><td>Angular planets as key roles</td><td>Zain 1949</td><td>10/10 events</td><td class=\"confirm\">Very High</td></tr>\n    <tr><td>Dwad positions (especially at angles)</td><td>Crane</td><td>10/10 events (decisive in many)</td><td class=\"confirm\">High — consistently resolves ambiguous readings</td></tr>\n    <tr><td>1°/day direction timing</td><td>Crane (from Zain tradition)</td><td>~5 events verified</td><td class=\"confirm\">High</td></tr>\n    <tr><td>Ceres angular = weather event</td><td>Crane</td><td>8+ events</td><td class=\"ambig\">High candidate — not yet in mainstream tradition</td></tr>\n    <tr><td>Pluto transit to national Sun = extended extreme</td><td>Crane</td><td>1975-76 drought</td><td class=\"ambig\">Medium — single case study, plausible</td></tr>\n    <tr><td>Sedna = coastal/maritime storms</td><td>Crane</td><td>1987 storm, 1953 flood, 1091 tornado</td><td class=\"ambig\">Medium — needs more data points</td></tr>\n    <tr><td>Eris = destructive/chaotic</td><td>Crane</td><td>3 events</td><td class=\"ambig\">Low-Medium — early hypothesis</td></tr>\n    <tr><td>Mercury as temperature indicator</td><td>Crane (observation only)</td><td>Qualitative observation</td><td class=\"ambig\">Low — needs systematic testing</td></tr>\n    <tr><td>Multi-zodiac approach</td><td>Crane</td><td>1946-47 (Sidereal decisive), 1962-63 (Draconic)</td><td class=\"ambig\">Medium — context-dependent; not always needed</td></tr>\n    <tr><td>Node sign change as weather indicator</td><td>Crane (tentative)</td><td>1 event (1962-63)</td><td class=\"fail\">Low — stated as untested by author</td></tr>\n  </tbody>\n</table>\n\n<!-- ═══════════════════════════════════════════════════════════════════ -->\n<div class=\"sep\"></div>\n<div class=\"note\" style=\"font-size:0.8rem; color: var(--muted);\">\n  <strong>Source:</strong> Rev. Pam Crane, \"Weather Forecasting,\" <em>The Adventurous Astrologer</em>, revpamcrane.weebly.com/weather-forecasting.html<br>\n  <strong>Primary Sources Cited by Crane:</strong> C. C. Zain, <em>Weather Predicting</em> (Brotherhood of Light, 1949); Kris Brandt Riske, <em>Astrometeorology</em> (1997).<br>\n  <strong>Framework compiled:</strong> May 2026 | For use in Geodetic Astrology prediction model backtesting.<br>\n  <strong>Note:</strong> All interpretations, patterns, and case studies are drawn directly from Crane's article. No external astrological systems or interpretations have been added.\n</div>";
